1	const BASE_PREMIUM = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	} as const;
9	
10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType; cursed?: boolean; enchantment?: number };
13	export type Customer = { yearsWithMHPCO: number };
14	export type QuoteOptions = { isFollowUp?: boolean };
15	
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
19	const LOYALTY_YEARS_THRESHOLD = 2;
20	const LOYALTY_DISCOUNT_RATE = 0.2;
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
26	const PROCESSING_FEE = 5;
27	
28	function itemSurcharge(item: Item): number {
29	  const base = BASE_PREMIUM[item.type];
30	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
31	  const enchantment =
32	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
33	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
34	      : 0;
35	  return cursed + enchantment;
36	}
37	
38	export function calculatePremium(items: Item[], customer?: Customer, options?: QuoteOptions): number {
39	  const groups = new Map<ItemType, number>();
40	  let totalSurcharge = 0;
41	  for (const item of items) {
42	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
43	    totalSurcharge += itemSurcharge(item);
44	  }
45	
46	  let total = 0;
47	  for (const [type, count] of groups) {
48	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
49	      total += BLOCK_PREMIUM;
50	    } else {
51	      total += count * BASE_PREMIUM[type];
52	    }
53	  }
54	  let policyPremium = total + totalSurcharge;
55	  if (customer && customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
56	    policyPremium *= 1 - LOYALTY_DISCOUNT_RATE;
57	  }
58	  policyPremium += policyPremium * FIRST_INSURANCE_SURCHARGE_RATE;
59	  if (options?.isFollowUp) {
60	    policyPremium *= 1 - FOLLOW_UP_DISCOUNT_RATE;
61	  }
62	  return Math.ceil(policyPremium + PROCESSING_FEE);
63	}
